// ─── Generate Open-Meteo batch requests for trade-critical climate zones ───
// Each zone monitors temperature and precipitation anomalies that could
// disrupt trade routes, ports, and commodity production regions.

const TRADE_CLIMATE_ZONES = [
  // Maritime chokepoints
  { name: 'Suez / Red Sea',      lat: 29.93, lon: 32.55, tradeRelevance: 'Suez Canal maritime traffic' },
  { name: 'Strait of Hormuz',    lat: 26.57, lon: 56.25, tradeRelevance: 'Oil/LNG tanker routes' },
  { name: 'Panama Canal Zone',   lat: 9.08,  lon: -79.68, tradeRelevance: 'Panama Canal water levels' },
  { name: 'Malacca Strait',      lat: 2.50,  lon: 101.50, tradeRelevance: 'Asia-Europe shipping lane' },
  { name: 'Taiwan Strait',       lat: 24.50, lon: 119.50, tradeRelevance: 'Semiconductor supply chain' },
  // Commodity production hubs
  { name: 'US Midwest (Grain)',   lat: 41.88, lon: -87.63, tradeRelevance: 'Wheat/corn production belt' },
  { name: 'Ukraine (Grain)',      lat: 48.38, lon: 31.17, tradeRelevance: 'Black Sea grain corridor' },
  { name: 'Brazil (Soy/Coffee)',  lat: -15.79, lon: -47.88, tradeRelevance: 'Major commodity exporter' },
  { name: 'Persian Gulf (Oil)',   lat: 25.29, lon: 51.53, tradeRelevance: 'Oil production & export hub' },
  { name: 'Australia (Mining)',   lat: -23.70, lon: 133.78, tradeRelevance: 'Iron ore, lithium, nickel' },
  { name: 'Chile (Copper)',       lat: -33.45, lon: -70.67, tradeRelevance: 'World copper supply' },
  { name: 'DRC (Cobalt)',         lat: -4.32, lon: 15.31, tradeRelevance: 'Cobalt/coltan mining' },
  // Major ports
  { name: 'Port Shanghai',       lat: 31.23, lon: 121.47, tradeRelevance: 'World busiest container port' },
  { name: 'Port Rotterdam',      lat: 51.95, lon: 4.12, tradeRelevance: 'Europe gateway port' },
  { name: 'Port Singapore',      lat: 1.26, lon: 103.84, tradeRelevance: 'Transshipment hub' },
];

const endDate = new Date().toISOString().slice(0, 10);
const startDate = new Date(Date.now() - 21 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);

const requests = TRADE_CLIMATE_ZONES.map(zone => ({
  zone,
  url: `https://archive-api.open-meteo.com/v1/archive?latitude=${zone.lat}&longitude=${zone.lon}&start_date=${startDate}&end_date=${endDate}&daily=temperature_2m_mean,precipitation_sum&timezone=auto`,
}));

return requests.map(r => ({ json: r }));

// ─── Climate Anomaly Detection & Trade Impact Scoring ───
// Compares last 7 days of observations against the 21-day baseline
// to detect temperature and precipitation anomalies.

const zone = $('Generate Zone Requests').item.json.zone;
const daily = $input.item.json.daily || {};
const times = daily.time || [];
const temps = daily.temperature_2m_mean || [];
const precips = daily.precipitation_sum || [];

if (times.length < 14) {
  return { json: { zone: zone.name, skipped: true, reason: 'insufficient data' } };
}

// Baseline: days 1–14, Recent: last 7 days
const baselineTemps = temps.slice(0, -7).filter(t => t != null);
const baselinePrecips = precips.slice(0, -7).filter(p => p != null);
const recentTemps = temps.slice(-7).filter(t => t != null);
const recentPrecips = precips.slice(-7).filter(p => p != null);

const avg = arr => arr.length ? arr.reduce((s, v) => s + v, 0) / arr.length : 0;

const baselineTempAvg = avg(baselineTemps);
const baselinePrecipAvg = avg(baselinePrecips);
const recentTempAvg = avg(recentTemps);
const recentPrecipAvg = avg(recentPrecips);

const tempDelta = Math.round((recentTempAvg - baselineTempAvg) * 10) / 10;
const precipDelta = Math.round((recentPrecipAvg - baselinePrecipAvg) * 10) / 10;

// Severity classification
const absTemp = Math.abs(tempDelta);
const absPrecip = Math.abs(precipDelta);
let severity = 'Normal';
if (absTemp >= 5 || absPrecip >= 12) severity = 'Extreme';
else if (absTemp >= 3 || absPrecip >= 6) severity = 'Moderate';

// Anomaly type
let type = 'Stable';
if (tempDelta > 3) type = 'Warm';
else if (tempDelta < -3) type = 'Cold';
else if (precipDelta > 6) type = 'Wet';
else if (precipDelta < -6) type = 'Dry';

// Trade impact assessment
let tradeImpact = 'None';
if (severity === 'Extreme') {
  tradeImpact = 'High — potential disruption to ' + zone.tradeRelevance;
} else if (severity === 'Moderate') {
  tradeImpact = 'Moderate — monitor ' + zone.tradeRelevance;
}

return {
  json: {
    zone: zone.name,
    location: { latitude: zone.lat, longitude: zone.lon },
    tradeRelevance: zone.tradeRelevance,
    tempDelta,
    precipDelta,
    severity,
    type,
    tradeImpact,
    period: `${times.slice(-7)[0]} to ${times[times.length - 1]}`,
    processedAt: new Date().toISOString(),
  }
};

// Aggregate all zone anomalies into a single payload
const anomalies = $input.all().map(i => i.json).filter(a => !a.skipped);
const extremeCount = anomalies.filter(a => a.severity === 'Extreme').length;
const moderateCount = anomalies.filter(a => a.severity === 'Moderate').length;

return [{
  json: {
    source: 'open-meteo',
    pipeline: 'climate-trade-anomalies',
    anomalies,
    summary: {
      totalZones: anomalies.length,
      extreme: extremeCount,
      moderate: moderateCount,
      normal: anomalies.length - extremeCount - moderateCount,
    },
    processedAt: new Date().toISOString(),
  }
}];
